func solve(s string) string {
    var result string

    for i := 0; i < len(s); i++ {
        char := s[i]

        if char == '*' {
            if len(result) > 0 {
                result = result[:len(result)-1]
            }
        } else if char == '#' {
            result += result
        } else if char == '%' {
            runes := []rune(result)
            for j, k := 0, len(runes)-1; j < k; j, k = j+1, k-1 {
                runes[j], runes[k] = runes[k], runes[j]
            }
            result = string(runes)
        } else {
            result += string(char)
        }
    }

    return result
}
